use std::collections::BTreeMap;

use crate::types::{JsonRule, PerfRegistryDetector};

pub fn generate_go_perf_metadata_code(
    rule_map: &BTreeMap<u32, JsonRule>,
    supported_ids: &[u32],
) -> String {
    crate::gen_metadata::generate_go_rule_metadata_code(
        "PERF",
        "perf_ref_slice!",
        "GO_PERF_RULE_IDS",
        rule_map,
        supported_ids,
    )
}

pub fn generate_go_perf_registry_code(detectors: &[PerfRegistryDetector]) -> String {
    let mut code = String::new();
    code.push_str(
        "// This file is auto-generated by build.rs from src/lang/go/detectors/perf/registry.toml\n",
    );
    code.push_str("// DO NOT EDIT MANUALLY\n\n");
    code.push_str("const GO_PERF_RULES: &[GoPerfEntry] = &[\n");
    for entry in detectors {
        let id = entry.perf;
        code.push_str(&format!(
            "    (\"PERF-{id}\", {}, &self::metadata::META_PERF_{id}),\n",
            entry.function
        ));
    }
    code.push_str("];\n");
    code.push_str("const _: () = assert!(!GO_PERF_RULES.is_empty());\n");
    code
}
